def gen(rng, size):
    n = max(3, min(size, 100000))
    queries = []
    seen = set()
    budget = max(1, min(size, 100000))
    def recurse(lo, hi, depth):
        if hi - lo <= 1 or depth > 6 or len(queries) >= budget:
            return
        if rng.random() < 0.7 and (lo, hi) not in seen:
            seen.add((lo, hi))
            queries.append([lo, hi])
            if rng.random() < 0.5:
                a = rng.randint(lo, hi - 2)
                b = rng.randint(a + 2, hi)
                recurse(a, b, depth + 1)
            else:
                mid = (lo + hi) // 2
                if mid - lo > 1:
                    recurse(lo, mid, depth + 1)
                if hi - mid > 1:
                    recurse(mid, hi, depth + 1)
        else:
            mid = (lo + hi) // 2
            if mid - lo > 1:
                recurse(lo, mid, depth + 1)
            if hi - mid > 1:
                recurse(mid, hi, depth + 1)
    recurse(0, n - 1, 0)
    rng.shuffle(queries)
    if not queries:
        queries = [[0, n - 1]]
    return [n, queries]

