class Solution:
    def shortestDistanceAfterQueries(self, n, queries):
        nxt = list(range(n))
        def find(x):
            root = x
            while nxt[root] != root:
                root = nxt[root]
            while nxt[x] != root:
                nxt[x], x = root, nxt[x]
            return root
        active = n
        ans = []
        for u, v in queries:
            x = find(u + 1)
            while x < v:
                nxt[x] = x + 1
                active -= 1
                x = find(x + 1)
            ans.append(active - 1)
        return ans

