var shortestDistanceAfterQueries = function(n, queries) {
    const nxt = new Array(n);
    for (let i = 0; i < n; i++) nxt[i] = i;
    const find = (x) => {
        let root = x;
        while (nxt[root] !== root) root = nxt[root];
        while (nxt[x] !== root) {
            const nextVal = nxt[x];
            nxt[x] = root;
            x = nextVal;
        }
        return root;
    };
    let active = n;
    const ans = [];
    for (const [u, v] of queries) {
        let x = find(u + 1);
        while (x < v) {
            nxt[x] = x + 1;
            active -= 1;
            x = find(x + 1);
        }
        ans.push(active - 1);
    }
    return ans;
};
